import './TableHeaderData.scss';

import { classNames } from ':helpers/classnames';
import type { FC } from 'react';
import React from 'react';
import type { TableHeaderDataProps } from './TableHeaderData.types';

export const TableHeaderData: FC<TableHeaderDataProps> = ({
	dense = false,
	alignRight = false,
	horizontalAlign,
	verticalAlign,
	className,
	children,
	expandable,
	...props
}) => {
	if (alignRight) {
		// eslint-disable-next-line no-console
		console.warn('Свойство alignRight устарело, используйте horizontalAlign="right"');
	}

	return (
		<th
			scope={horizontalAlign ? 'row' : 'col'}
			data-testid="TableHeaderData"
			{...props}
			className={classNames(
				'dsb_table-header-cell',
				'dsb_table-header-cell__header',
				dense && 'dsb_table-header-cell__dense',
				alignRight && !horizontalAlign && 'dsb_table-header-cell__horizontal-align-right',
				horizontalAlign && `dsb_table-header-cell__horizontal-align-${horizontalAlign}`,
				verticalAlign && `dsb_table-header-cell__vertical-align-${verticalAlign}`,
				expandable && 'dsb_table-header-cell__expandable',
				className,
			)}
		>
			<div className={classNames('dsb_table-header-cell_flex')}>{children}</div>
		</th>
	);
};
